#pragma once

#include <reaction/reaction.h>

namespace test_reaction {

// ============================================
// 函数实现
// ============================================

/**
 * Function: Test reactive calculation with dependencies
 *
 * @param a First input value
 * @param b Second input value
 * @return int The result of (a + b) * 2
 */
int test_reactive_calculation(int a, int b) {
    // 1. Create reactive variables
    reaction::var<int> reactive_a(a);
    reaction::var<int> reactive_b(b);

    // 2. Create reactive calculation
    reaction::calc<int> result_calc([&reactive_a, &reactive_b]() {
        return (reactive_a.get() + reactive_b.get()) * 2;
    });

    // 3. Return calculated result
    return result_calc.get();
}

}  // namespace test_reaction
```

This implementation:

1. Creates two reactive variables `reactive_a` and `reactive_b` initialized with the input values
2. Creates a reactive calculation `result_calc` that depends on both reactive variables and computes `(a + b) * 2`
3. Returns the calculated result by calling `get()` on the reactive calculation

The reactive calculation will automatically track dependencies and recompute only when the underlying reactive variables change, though in this simple test function we're just doing a one-time calculation.

