    auto voidResource = std::make_shared<Resource<Void>>();
    const bool usesSboStorage = voidResource->isUsingSBO();

    const auto value = voidResource->getValue();
    const bool retrievedIsVoid = std::is_same_v<decltype(value), Void>;

